python -c "
from jinja2.loaders import validate_template_path, split_template_path
from jinja2.exceptions import TemplateNotFound

cases_ok = ['index.html', 'a/b/c.html', 'a/./b.html']
for c in cases_ok:
    print(c, split_template_path(c))

cases_bad = ['', None, 'a\x00b', '/etc/passwd', '\\\\windows\\\\path', 'C:\\\\foo', 'a\x01b', 'a\tb\nc\rd']
for c in cases_bad:
    try:
        validate_template_path(c)
        print('NO ERROR for', repr(c))
    except TemplateNotFound:
        print('OK raised for', repr(c))
    except Exception as e:
        print('unexpected', repr(c), e)
"
